package com.banking.service.impl;

import com.banking.exception.BankingException;
import com.banking.exception.BankingFault;
import com.banking.model.AccountBalance;
import com.banking.model.Transaction;
import com.banking.model.TransactionResponse;
import com.banking.service.BankingService;

import javax.jws.WebService;
import java.math.BigDecimal;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    endpointInterface = "com.banking.service.BankingService",
    targetNamespace = "http://banking.com/service",
    wsdlLocation = "WEB-INF/wsdl/BankingService.wsdl"
)
public class BankingServiceImpl implements BankingService {

    private static final Logger LOGGER = Logger.getLogger(BankingServiceImpl.class.getName());

    // Simulated account store
    private static final ConcurrentHashMap<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();
    private static final ConcurrentHashMap<String, List<Transaction>> transactionStore = new ConcurrentHashMap<>();
    private static final Set<String> validAccounts = ConcurrentHashMap.newKeySet();

    static {
        accountBalances.put("ACC-001", new BigDecimal("50000.00"));
        accountBalances.put("ACC-002", new BigDecimal("25000.00"));
        accountBalances.put("ACC-003", new BigDecimal("100000.00"));
        accountBalances.put("ACC-004", new BigDecimal("75000.00"));
        validAccounts.addAll(Arrays.asList("ACC-001", "ACC-002", "ACC-003", "ACC-004"));
    }

    @Override
    public TransactionResponse processTransfer(Transaction transaction) throws BankingException {
        LOGGER.info("Processing transfer: " + transaction.getTransactionId());

        validateTransaction(transaction);

        String sourceAccount = transaction.getSourceAccount();
        String targetAccount = transaction.getTargetAccount();
        BigDecimal amount = transaction.getAmount();

        synchronized (this) {
            BigDecimal sourceBalance = accountBalances.get(sourceAccount);
            if (sourceBalance == null) {
                throw createBankingException("ACCOUNT_NOT_FOUND",
                    "Source account not found", "Account: " + sourceAccount);
            }

            if (sourceBalance.compareTo(amount) < 0) {
                throw createBankingException("INSUFFICIENT_FUNDS",
                    "Insufficient funds in source account",
                    "Available: " + sourceBalance + ", Required: " + amount);
            }

            accountBalances.put(sourceAccount, sourceBalance.subtract(amount));

            BigDecimal targetBalance = accountBalances.getOrDefault(targetAccount, BigDecimal.ZERO);
            accountBalances.put(targetAccount, targetBalance.add(amount));

            storeTransaction(sourceAccount, transaction);
            storeTransaction(targetAccount, transaction);
        }

        LOGGER.info("Transfer completed successfully: " + transaction.getTransactionId());
        return new TransactionResponse(
            transaction.getTransactionId(), "SUCCESS", 200, "Transfer processed successfully"
        );
    }

    @Override
    public AccountBalance getAccountBalance(String accountNumber) throws BankingException {
        LOGGER.info("Retrieving balance for account: " + accountNumber);

        if (accountNumber == null || accountNumber.trim().isEmpty()) {
            throw createBankingException("INVALID_INPUT",
                "Account number is required", "Account number was null or empty");
        }

        if (!validAccounts.contains(accountNumber)) {
            throw createBankingException("ACCOUNT_NOT_FOUND",
                "Account not found", "Account: " + accountNumber);
        }

        BigDecimal balance = accountBalances.getOrDefault(accountNumber, BigDecimal.ZERO);
        return new AccountBalance(accountNumber, balance, balance, "USD");
    }

    @Override
    public TransactionResponse processPayment(Transaction transaction) throws BankingException {
        LOGGER.info("Processing payment: " + transaction.getTransactionId());

        validateTransaction(transaction);

        String sourceAccount = transaction.getSourceAccount();
        BigDecimal amount = transaction.getAmount();

        synchronized (this) {
            BigDecimal sourceBalance = accountBalances.get(sourceAccount);
            if (sourceBalance == null) {
                throw createBankingException("ACCOUNT_NOT_FOUND",
                    "Account not found", "Account: " + sourceAccount);
            }

            if (sourceBalance.compareTo(amount) < 0) {
                throw createBankingException("INSUFFICIENT_FUNDS",
                    "Insufficient funds", "Available: " + sourceBalance + ", Required: " + amount);
            }

            accountBalances.put(sourceAccount, sourceBalance.subtract(amount));
            storeTransaction(sourceAccount, transaction);
        }

        LOGGER.info("Payment completed successfully: " + transaction.getTransactionId());
        return new TransactionResponse(
            transaction.getTransactionId(), "SUCCESS", 200, "Payment processed successfully"
        );
    }

    @Override
    public List<Transaction> getTransactionHistory(String accountNumber, int limit) throws BankingException {
        LOGGER.info("Retrieving transaction history for: " + accountNumber);

        if (accountNumber == null || accountNumber.trim().isEmpty()) {
            throw createBankingException("INVALID_INPUT",
                "Account number is required", null);
        }

        if (!validAccounts.contains(accountNumber)) {
            throw createBankingException("ACCOUNT_NOT_FOUND",
                "Account not found", "Account: " + accountNumber);
        }

        List<Transaction> history = transactionStore.getOrDefault(accountNumber, Collections.emptyList());
        int effectiveLimit = Math.min(limit, history.size());
        return history.subList(0, effectiveLimit);
    }

    @Override
    public boolean validateAccount(String accountNumber) throws BankingException {
        if (accountNumber == null || accountNumber.trim().isEmpty()) {
            throw createBankingException("INVALID_INPUT",
                "Account number is required", null);
        }
        return validAccounts.contains(accountNumber);
    }

    private void validateTransaction(Transaction transaction) throws BankingException {
        if (transaction == null) {
            throw createBankingException("INVALID_INPUT", "Transaction is null", null);
        }
        if (transaction.getTransactionId() == null || transaction.getTransactionId().trim().isEmpty()) {
            throw createBankingException("INVALID_INPUT", "Transaction ID is required", null);
        }
        if (transaction.getSourceAccount() == null || transaction.getSourceAccount().trim().isEmpty()) {
            throw createBankingException("INVALID_INPUT", "Source account is required", null);
        }
        if (transaction.getAmount() == null || transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw createBankingException("INVALID_AMOUNT", "Amount must be positive", null);
        }
        if (transaction.getAmount().compareTo(new BigDecimal("1000000")) > 0) {
            throw createBankingException("AMOUNT_EXCEEDED",
                "Transaction amount exceeds maximum limit", "Max: 1,000,000");
        }
    }

    private void storeTransaction(String accountNumber, Transaction transaction) {
        transactionStore.computeIfAbsent(accountNumber, k -> Collections.synchronizedList(new ArrayList<>()))
                        .add(transaction);
    }

    private BankingException createBankingException(String code, String message, String details) {
        BankingFault fault = new BankingFault(code, message, details);
        return new BankingException(message, fault);
    }
}

