package com.banking.security;

import org.apache.wss4j.common.ext.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.logging.Logger;

public class ServerPasswordCallback implements CallbackHandler {

    private static final Logger LOGGER = Logger.getLogger(ServerPasswordCallback.class.getName());

    // In production, load from secure vault or HSM
    private static final Map<String, String> passwords = new HashMap<>();
    private static final Map<String, String> keystorePasswords = new HashMap<>();

    static {
        // Username/password pairs for UsernameToken
        passwords.put("bankingAdmin", "SecureP@ss2024!");
        passwords.put("apiClient", "Cl!entS3cret");
        passwords.put("serviceAccount", "S3rv!ceP@ss");

        // Keystore passwords for signature/encryption
        keystorePasswords.put("server-key", "serverKeyPassword");
        keystorePasswords.put("banking-service", "bankingServicePassword");
    }

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                String identifier = pc.getIdentifier();
                int usage = pc.getUsage();

                LOGGER.info("Password callback for identifier: " + identifier + ", usage: " + usage);

                switch (usage) {
                    case WSPasswordCallback.USERNAME_TOKEN:
                        handleUsernameToken(pc, identifier);
                        break;
                    case WSPasswordCallback.DECRYPT:
                    case WSPasswordCallback.SIGNATURE:
                        handleKeystorePassword(pc, identifier);
                        break;
                    default:
                        handleDefaultPassword(pc, identifier);
                        break;
                }
            } else {
                throw new UnsupportedCallbackException(callback, "Unrecognized callback type");
            }
        }
    }

    private void handleUsernameToken(WSPasswordCallback pc, String identifier) throws IOException {
        String password = passwords.get(identifier);
        if (password != null) {
            pc.setPassword(password);
        } else {
            LOGGER.warning("Unknown user: " + identifier);
            throw new IOException("Authentication failed for user: " + identifier);
        }
    }

    private void handleKeystorePassword(WSPasswordCallback pc, String identifier) throws IOException {
        String password = keystorePasswords.get(identifier);
        if (password != null) {
            pc.setPassword(password);
        } else {
            LOGGER.warning("Unknown key alias: " + identifier);
            throw new IOException("Key not found: " + identifier);
        }
    }

    private void handleDefaultPassword(WSPasswordCallback pc, String identifier) throws IOException {
        String password = passwords.get(identifier);
        if (password == null) {
            password = keystorePasswords.get(identifier);
        }
        if (password != null) {
            pc.setPassword(password);
        } else {
            throw new IOException("No password found for: " + identifier);
        }
    }
}

